    n = int(input())
    a = list(map(int, input().split()))
    a_set = set(a)

    def check(b):
        diffs = set()
        for x in b:
            for y in b:
                diffs.add(x - y)
        return a_set.issubset(diffs)

    # backtracking
    def bt(b):
        if len(b) == n:
            return check(b)
        # compute current diffs
        diffs = set()
        for x in b:
            for y in b:
                diffs.add(x - y)
        # find uncovered a values
        uncovered = [v for v in a_set if v not in diffs]
        if not uncovered:
            # fill remaining with any value (e.g., 0)
            # but we need exactly n elements
            # just duplicate b[0]
            new_b = b + [b[0]] * (n - len(b))
            return True  # already covered
        # try candidates: b[j] + uncovered[0] or b[j] - uncovered[0]
        v = uncovered[0]
        candidates = set()
        for bj in b:
            candidates.add(bj + v)  # new - bj = v => new = bj + v
            candidates.add(bj - v)  # bj - new = v => new = bj - v
        for c in candidates:
            if bt(b + [c]):
                return True
        return False

    if bt([0]):
        print("YES")
    else:
        print("NO")

